// hooks and interceptors per client, for fast access.
type (
	hooks struct {
		Document, DocumentSnapshot, Project, ProjectGroupShare, ProjectShare, Tenant,
		User []ent.Hook
	}
	inters struct {
		Document, DocumentSnapshot, Project, ProjectGroupShare, ProjectShare, Tenant,
		User []ent.Interceptor
	}
)
